SELECT leaf_1.region_name, leaf_1.payment_no, leaf_1.payment_dt, leaf_1.payment_amt, leaf_1.category_desc FROM (SELECT m.region_no, r.region_name, p.payment_no, p.payment_dt, p.payment_amt, c.category_no, cat.category_desc FROM payment AS p JOIN member AS m ON p.member_no = m.member_no JOIN region AS r ON m.region_no = r.region_no LEFT JOIN charge AS c ON p.member_no = c.member_no LEFT JOIN category AS cat ON c.category_no = cat.category_no WHERE (cat.category_desc = 'Lodging' OR cat.category_desc IS NULL) GROUP BY m.region_no, r.region_name, p.payment_no, p.payment_dt, p.payment_amt, c.category_no, cat.category_desc) AS leaf_1 GROUP BY leaf_1.region_name, leaf_1.payment_no, leaf_1.payment_dt, leaf_1.payment_amt, leaf_1.category_desc
